def _stamp() -> str:
    return time.strftime("%Y%m%dT%H%M%SZ", time.gmtime())


def _root() -> Path:
    return Path(__file__).resolve().parents[1]


def _backup(path: Path, backup_root: Path, root: Path) -> str | None:
    if not path.exists():
        return None
    rel = path.relative_to(root)
    dest = backup_root / rel
    dest.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(path, dest)
    return rel.as_posix()


def _replace_source_gate(module_path: Path) -> dict[str, object]:
    if not module_path.exists():
        return {"patched": False, "path": module_path.as_posix(), "reason": "target_module_missing"}
    text = module_path.read_text(encoding="utf-8")
    start = text.find("def evaluate_source_33g_gate(")
    end = text.find("def build_immutable_plan_digest(", start)
    if start < 0 or end < 0:
        return {"patched": False, "path": module_path.as_posix(), "reason": "source_gate_bounds_not_found"}
    current = text[start:end]
    if "both summary and full run-report schemas" in current:
        return {"patched": True, "path": module_path.as_posix(), "reason": "already_patched"}
    new_text = text[:start] + NEW_EVALUATE_SOURCE_33G_GATE.strip("\n") + "\n\n" + text[end:]
    module_path.write_text(new_text, encoding="utf-8", newline="\n")
    return {"patched": True, "path": module_path.as_posix(), "reason": "source_33g_gate_replaced"}


def main() -> int:
    root = _root()
    backup_root = root / "tools" / f"_patch_backup_{PATCH_ID}_{_stamp()}"
    backed_up: list[str] = []
    written: list[str] = []
    modified: list[str] = []

    target = root / TARGET_MODULE
    backup_rel = _backup(target, backup_root, root)
    if backup_rel:
        backed_up.append(backup_rel)
    patch_result = _replace_source_gate(target)
    if patch_result.get("patched") is True:
        modified.append(TARGET_MODULE)

    for rel, content in PAYLOADS.items():
        path = root / rel
        backup_rel = _backup(path, backup_root, root)
        if backup_rel:
            backed_up.append(backup_rel)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content.lstrip("\n"), encoding="utf-8", newline="\n")
        written.append(rel)

    compile_targets = [TARGET_MODULE] + [rel for rel in PAYLOADS if rel.endswith(".py")]
    compile_errors: dict[str, str] = {}
    for rel in compile_targets:
        try:
            py_compile.compile(str(root / rel), doraise=True)
        except Exception as exc:
            compile_errors[rel] = f"{type(exc).__name__}: {exc}"

    if not backed_up and backup_root.exists():
        shutil.rmtree(backup_root)
        backup_root_str = ""
    else:
        backup_root_str = str(backup_root.relative_to(root)) if backed_up else ""

    result = {
        "applied": bool(patch_result.get("patched")) and not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "source_gate_patch_result": patch_result,
        "modified_files": modified,
        "written_files": written,
        "backed_up_files": backed_up,
        "backup_root": backup_root_str,
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_exchange_submit": False,
        "approved_for_runtime_overlay": False,
        "archive_execution_allowed": False,
        "archive_move_performed": False,
        "file_delete_performed": False,
        "destructive_cleanup_performed": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "exchange_submit_performed": False,
        "runtime_overlay_activated": False,
    }
    print(json.dumps(result, indent=2, sort_keys=True))
    return 0 if result["applied"] else 1


if __name__ == "__main__":
    raise SystemExit(main())
